import java.util.ArrayList;
import java.util.List;

public class Solution {
    public static long solve(long[] nums) {
        // The problem asks for the maximum number of fixed points achievable after deleting any number of elements.
        // If we keep a subsequence of the original array, say nums[i_0], nums[i_1], ..., nums[i_{k-1}],
        // where i_0 < i_1 < ... < i_{k-1}, the new array will have length k.
        // The element nums[i_j] will be at index j in the new array.
        // A fixed point occurs at index j if the element at that index equals j, i.e., nums[i_j] == j.

        // We want to find the longest subsequence such that for the j-th element of the subsequence (0-indexed),
        // its value is equal to its new index j.

        // This is a classic Longest Increasing Subsequence (LIS) type problem, but with a specific condition:
        // We are looking for the longest sequence of indices i_0 < i_1 < ... < i_{k-1} such that nums[i_j] = j.

        // Let's iterate through the original array and try to build the longest possible sequence.

        // `target_value` will track the index of the *next* fixed point we are trying to form.
        // If we have successfully formed k fixed points (indices 0 to k-1 in the resulting array), 
        // the next fixed point must be at index k, and its value must be k.

        int current_fixed_points = 0;

        for (int i = 0; i < nums.length; i++) {
            // If the value of the current element nums[i] matches the index we are currently looking for (current_fixed_points),
            // then we can choose to keep this element to be the next fixed point.
            if (nums[i] == current_fixed_points) {
                // By keeping this element, we successfully form a fixed point at index current_fixed_points.
                // We increment the count and look for the next fixed point (at index current_fixed_points + 1).
                current_fixed_points++;
            }
            // If nums[i] != current_fixed_points, we *must* skip this element (delete it) if we want to maintain the property 
            // for the current sequence, because keeping it would place it at an index j where nums[i] != j.
            // If we skip it, we still look for current_fixed_points at the next element.
        }

        // current_fixed_points now holds the maximum length of such a subsequence, which is the maximum number of fixed points.
        return current_fixed_points;
    }
}
