class Solution {
    /**
     * Returns the maximum number of fixed points achievable after deleting any number of elements.
     *
     * @param nums The input integer array.
     * @return The maximum number of fixed points.
     */
    public static long solve(long[] nums) {
        int n = nums.length;

        // The problem is equivalent to finding the maximum length of a subsequence 
        // of nums such that for all elements in the subsequence at index i, 
        // the value is equal to i.
        // Let the subsequence be s = [nums[i1], nums[i2], ..., nums[ik]] 
        // where i1 < i2 < ... < ik.
        // After deletion, the element nums[ij] will be at index j-1.
        // We want nums[ij] == j-1 for all j=1 to k.
        // This means we are looking for the longest subsequence where the element 
        // at the j-th position (0-indexed) must be equal to j.

        // This is a variation of the Longest Increasing Subsequence (LIS) problem,
        // but simpler because the target values are strictly determined by the position.

        // We can use a greedy approach. We iterate through the original array nums 
        // and try to keep an element if it matches the required index in the resulting sequence.

        int currentFixedPoints = 0;

        for (int i = 0; i < n; i++) {
            // If we keep nums[i], it will be placed at index 'currentFixedPoints' 
            // in the resulting array (since 'currentFixedPoints' is the count of elements kept so far).

            // For it to be a fixed point, its value must equal its new index.
            if (nums[i] == currentFixedPoints) {
                // We choose to keep this element, increasing the potential fixed point count.
                currentFixedPoints++;
            }
            // If nums[i] != currentFixedPoints, we must delete it to maintain the 
            // possibility of maximizing fixed points with later elements, 
            // as keeping it would violate the fixed point condition for this position.
        }

        return currentFixedPoints;
    }
}
