class Solution {
    /**
     * Returns the maximum number of fixed points achievable after deleting any number of elements.
     * 
     * The problem asks for the maximum size of a subsequence that forms an identity sequence (0, 1, 2, ...).
     * If we select a subsequence of indices $i_1, i_2, \ldots, i_k$ from the original array `nums`,
     * where $i_1 < i_2 < \ldots < i_k$, the new array will be $nums[i_1], nums[i_2], \ldots, nums[i_k]$.
     * A fixed point occurs at position $j$ if the element at that position equals $j$.
     * For the subsequence to have $k$ fixed points, we must have:
     * $nums[i_1] = 0$
     * $nums[i_2] = 1$
     * $\ldots$
     * $nums[i_k] = k-1$
     * 
     * This is equivalent to finding the Longest Increasing Subsequence (LIS) where the "increasing"
     * condition is specifically $nums[i_j] = j-1$ for the $j$-th element in the subsequence.
     * 
     * Let $k$ be the number of fixed points we want to achieve. We are looking for the longest sequence
     * of indices $i_0, i_1, \ldots, i_{k-1}$ such that:
     * 1. $0 \le i_0 < i_1 < \ldots < i_{k-1} < n$
     * 2. $nums[i_j] = j$ for all $j=0, 1, \ldots, k-1$.
     * 
     * This can be solved using a greedy approach or dynamic programming, but a simple greedy scan works.
     * We look for the smallest index $i_0$ such that $nums[i_0] = 0$.
     * Then, we look for the smallest index $i_1 > i_0$ such that $nums[i_1] = 1$.
     * And so on.
     */
    public static long solve(long[] nums) {
        int n = nums.length;

        // 'target' represents the value we are currently looking for in the subsequence: 0, 1, 2, ...
        int target = 0; 
        // 'current_index' tracks the starting point for the search (must be greater than the previously selected index).
        int current_index = -1; 
        int max_fixed_points = 0;

        // Iterate through the original array to find the elements forming the subsequence (0, 1, 2, ...)
        for (int i = 0; i < n; i++) {
            // We only care about elements whose value matches the next required fixed point index (target)
            // AND this element must appear strictly after the last chosen element (i > current_index).
            if (nums[i] == target) {
                // Found the required element for the next fixed point
                max_fixed_points++;
                target++;
                // Update the position of the last selected element
                current_index = i;
            }
        }

        return max_fixed_points;
    }
}
